// // This module implements a 10-bit synchronous counter with enable, load, and clear signals.
// The counter decrements when enable is high, loads a given value when load is high,
// and clears to 0 when clear is high. The count value should be output as a 10-bit bus.
module top_module(
	input clk,
	input enable,
	input load,
	input clear,
	input [9:0] load_value,
	output reg [9:0] count);
always @(posedge clk) begin
	if (clear)
		count <= 0;
	else if (load)
		count <= load_value;
	else if (enable)
		count <= count + 1;
end

endmodule

